<template>
  <div id="app">
    <nav class="navbar bg-light sticky-top" v-show="installBtn"> 
        <div>
          <small>Install <b> Serenity </b> on your device.</small>
        </div>
      <div class="row justify-content-end m-0">
        <b-button variant="info" class="text-right" @click="installer()">
        Install
      </b-button>
      </div>
    </nav>
    <transition appear name="custom-classes-transition" enter-active-class="animated fadeIn">
        <router-view/>
    </transition>
    <vue-snotify></vue-snotify>
  </div>
</template>

<script>
import { mapState } from "vuex";

export default {
  data(){
    return{
      installBtn: false,
     installer: undefined
    }
  },
  methods:{
    
  },
  // computed:{
  //   ...mapState({
  //     Reg: state => state.reg,
  //   }),
  // },
  created(){
    let installPrompt;
    window.addEventListener("beforeinstallprompt", e => {
      e.preventDefault();
      
      installPrompt = e;
      this.installBtn = true;
    });

    this.installer = () => {
      this.installBtn = false;

      installPrompt.prompt();

      installPrompt.userChioce.then(result => {
        installPrompt = null
      })
    }
  },
  mounted() {
    
  },
}
</script>

